const RE = /^[a-z0-9]([a-z0-9-]{0,61}[a-z0-9])?$/;
function bad(s){ return !s || typeof s !== "string" || !RE.test(s); }
const i = $input.first().json;
if (bad(i.namespace) || bad(i.name)) return [{json: {blocked: true, ok: false, detail: "invalid or missing namespace/name"}}];
return [{json: {url: `https://kubernetes.default.svc/apis/apps/v1/namespaces/${i.namespace}/deployments/${i.name}`}}];

const r = $input.first().json;
if (r.blocked) return [{json: {ok: false, detail: r.detail}}];
if (r.statusCode >= 400) return [{json: {ok: false, detail: `K8s API ${r.statusCode}: ${JSON.stringify(r.body?.message).slice(0,200)}`}}];
const d = r.body;
return [{json: {ok: true, deployment: {
  name: d.metadata.name, namespace: d.metadata.namespace,
  replicas: {desired: d.spec.replicas, ready: d.status.readyReplicas||0, available: d.status.availableReplicas||0, updated: d.status.updatedReplicas||0},
  strategy: d.spec.strategy?.type,
  containers: (d.spec.template.spec.containers||[]).map(c => ({name: c.name, image: c.image, resources: c.resources})),
  conditions: (d.status.conditions||[]).map(c => `${c.type}=${c.status} (${c.reason||""})`)
}}}];
